interface MonthYearSelectorProps {
  currentDate: Date;
  onChange: (date: Date) => void;
  onClose: () => void;
}

export const MonthYearSelector: React.FC<MonthYearSelectorProps> = ({ currentDate, onChange, onClose }) => {
  const [viewYear, setViewYear] = useState(currentDate.getFullYear());

  const handleMonthSelect = (monthIndex: number) => {
    // Navigate to the selected month/year, resetting to day 1 to avoid overflow
    const newDate = new Date(viewYear, monthIndex, 1);
    onChange(newDate);
  };

  return (
      <div 
        className="absolute top-full mt-2 left-1/2 -translate-x-1/2 bg-white rounded-xl shadow-xl border border-gray-100 p-4 w-64 z-50 animate-in fade-in zoom-in-95 duration-200"
      >
        <div className="flex items-center justify-between mb-4">
          <button
            type="button"
            onClick={(e) => { e.stopPropagation(); setViewYear(y => y - 1); }}
            className="p-1 hover:bg-gray-100 rounded-lg text-gray-600 transition-colors"
          >
            <ChevronLeft size={20} />
          </button>
          <span className="text-lg font-bold text-gray-800 select-none">{viewYear}</span>
          <button
            type="button"
            onClick={(e) => { e.stopPropagation(); setViewYear(y => y + 1); }}
            className="p-1 hover:bg-gray-100 rounded-lg text-gray-600 transition-colors"
          >
            <ChevronRight size={20} />
          </button>
        </div>
        <div className="grid grid-cols-3 gap-2">
          {MONTH_NAMES.map((month, index) => (
            <button
              key={month}
              type="button"
              onClick={(e) => { e.stopPropagation(); handleMonthSelect(index); }}
              className={`
                p-2 rounded-lg text-sm font-medium transition-colors
                ${index === currentDate.getMonth() && viewYear === currentDate.getFullYear()
                  ? 'bg-blue-600 text-white shadow-sm'
                  : 'text-gray-700 hover:bg-gray-100'
                }
              `}
            >
              {month.substring(0, 3)}
            </button>
          ))}
        </div>
      </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, Plus, Calendar as CalendarLogo } from 'lucide-react';
import { CalendarEvent, Region, DayData } from './types';
import { 
    generateCalendarGrid, 
    MONTH_NAMES, 
    WEEK_DAYS, 
    isSameDay, 
    isDateInRange,
    formatTime,
    getRegionClasses 
} from './utils/dateUtils';
import { EventModal } from './components/EventModal';
import { MonthYearSelector } from './components/MonthYearSelector';

const App: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);

  // Modals state
  const [isEventModalOpen, setIsEventModalOpen] = useState(false);
  const [isMonthPickerOpen, setIsMonthPickerOpen] = useState(false);

  const monthPickerRef = useRef<HTMLDivElement>(null);
  const scrollCooldown = useRef(false);

  // Load events from local storage on mount
  useEffect(() => {
    const savedEvents = localStorage.getItem('lumina_events');
    if (savedEvents) {
      try {
        const parsed = JSON.parse(savedEvents);
        // Migration: Ensure all events have a region. Default to IWAMI if missing.
        const migratedEvents = parsed.map((e: any) => ({
            ...e,
            region: e.region || Region.IWAMI
        }));
        setEvents(migratedEvents);
      } catch (e) {
        console.error("Failed to parse events", e);
      }
    }
  }, []);

  // Save events to local storage whenever they change
  useEffect(() => {
    localStorage.setItem('lumina_events', JSON.stringify(events));
  }, [events]);

  // Handle click outside for month picker
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (monthPickerRef.current && !monthPickerRef.current.contains(event.target as Node)) {
        setIsMonthPickerOpen(false);
      }
    };

    if (isMonthPickerOpen) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [isMonthPickerOpen]);

  const handlePrevMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
  };

  const handleJumpToToday = () => {
    setCurrentDate(new Date());
  };

  const handleDateClick = (date: Date) => {
    setSelectedDate(date);
    setSelectedEvent(null);
    setIsEventModalOpen(true);
  };

  const handleEventClick = (e: React.MouseEvent, event: CalendarEvent) => {
    e.stopPropagation();
    setSelectedEvent(event);
    setSelectedDate(new Date(event.start));
    setIsEventModalOpen(true);
  };

  const handleSaveEvent = (event: CalendarEvent) => {
    setEvents(prev => {
      const exists = prev.find(e => e.id === event.id);
      if (exists) {
        return prev.map(e => e.id === event.id ? event : e);
      }
      return [...prev, event];
    });
  };

  const handleDeleteEvent = (id: string) => {
    setEvents(prev => prev.filter(e => e.id !== id));
  };

  const handleWheel = (e: React.WheelEvent) => {
    // Prevent interfering with other interactions or rapid firing
    if (scrollCooldown.current) return;

    // Check if scrolling inside a scrollable event list (has overflow-y-auto class)
    const target = e.target as HTMLElement;
    const scrollableContainer = target.closest('.overflow-y-auto');

    if (scrollableContainer) {
        const el = scrollableContainer as HTMLElement;
        // If the element has scrollable content, allow native scrolling
        if (el.scrollHeight > el.clientHeight) {
            return;
        }
    }

    // Significant scroll threshold to avoid accidental triggers
    if (Math.abs(e.deltaY) < 20) return;

    scrollCooldown.current = true;

    if (e.deltaY > 0) {
        handleNextMonth();
    } else {
        handlePrevMonth();
    }

    // Cooldown period
    setTimeout(() => {
        scrollCooldown.current = false;
    }, 500);
  };

  const gridData = generateCalendarGrid(currentDate);

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 text-gray-900 font-sans">
      {/* Header */}
      <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-gray-200 px-6 py-4 flex flex-col md:flex-row items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-xl text-white shadow-lg shadow-blue-200">
                <CalendarLogo size={24} />
            </div>
            <h1 className="text-2xl font-bold tracking-tight text-gray-800">AJET Event Calendar</h1>
        </div>

        <div className="flex items-center gap-4 bg-gray-100/50 p-1.5 rounded-2xl border border-gray-200/50">
            <button 
                onClick={handlePrevMonth}
                className="p-2 hover:bg-white rounded-xl text-gray-600 transition-all shadow-sm hover:shadow-md"
            >
                <ChevronLeft size={20} />
            </button>

            <div className="relative" ref={monthPickerRef}>
                <button
                    onClick={() => setIsMonthPickerOpen(!isMonthPickerOpen)}
                    className="px-3 py-1 hover:bg-white rounded-xl text-gray-800 transition-all shadow-sm hover:shadow-md border border-transparent hover:border-gray-200 min-w-[140px]"
                >
                    <span className="text-lg font-semibold select-none block text-center">
                        {MONTH_NAMES[currentDate.getMonth()]} {currentDate.getFullYear()}
                    </span>
                </button>
                {isMonthPickerOpen && (
                    <MonthYearSelector 
                        currentDate={currentDate} 
                        onChange={(date) => {
                            setCurrentDate(date);
                            setIsMonthPickerOpen(false);
                        }}
                        onClose={() => setIsMonthPickerOpen(false)}
                    />
                )}
            </div>

            <button 
                onClick={handleNextMonth}
                className="p-2 hover:bg-white rounded-xl text-gray-600 transition-all shadow-sm hover:shadow-md"
            >
                <ChevronRight size={20} />
            </button>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
            <button 
                onClick={handleJumpToToday}
                className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors border border-gray-200 bg-white"
            >
                Today
            </button>
            <button 
                onClick={() => {
                    setSelectedDate(null);
                    setSelectedEvent(null);
                    setIsEventModalOpen(true);
                }}
                className="flex items-center justify-center p-2 text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-all shadow-md shadow-blue-100 hover:shadow-lg"
            >
                <Plus size={20} />
            </button>
        </div>
      </header>

      {/* Main Grid */}
      <main 
        className="flex-1 p-4 md:p-6 overflow-hidden flex flex-col"
        onWheel={handleWheel}
      >
        {/* Days Header */}
        <div className="grid grid-cols-7 mb-4">
            {WEEK_DAYS.map(day => (
                <div key={day} className="text-center text-sm font-semibold text-gray-400 uppercase tracking-wider">
                    {day}
                </div>
            ))}
        </div>

        {/* Calendar Grid */}
        <div className="flex-1 grid grid-cols-7 grid-rows-6 gap-2 md:gap-4 min-h-[600px]">
            {gridData.map((cell, index) => {
                const isToday = isSameDay(cell.date, new Date());
                const dayEvents = events.filter(e => isDateInRange(cell.date, e.start, e.end, e.isAllDay))
                                        .sort((a, b) => new Date(a.start).getTime() - new Date(b.start).getTime());

                return (
                    <div 
                        key={index} 
                        className={`
                            relative bg-white rounded-2xl p-2 border border-gray-100 
                            transition-all hover:shadow-md flex flex-col gap-1 overflow-hidden group
                            ${!cell.isCurrentMonth ? 'bg-gray-50/50 text-gray-400' : 'text-gray-700'}
                            ${isToday ? 'ring-2 ring-blue-500 ring-offset-2' : ''}
                        `}
                    >
                        <div className="flex justify-between items-start">
                            <span className={`
                                text-sm font-medium w-7 h-7 flex items-center justify-center rounded-full
                                ${isToday ? 'bg-blue-600 text-white' : ''}
                            `}>
                                {cell.date.getDate()}
                            </span>
                        </div>

                        {/* Events List */}
                        <div className="flex-1 flex flex-col gap-1 overflow-y-auto custom-scrollbar mt-1">
                            {dayEvents.map(event => (
                                <div 
                                    key={event.id}
                                    onClick={(e) => handleEventClick(e, event)}
                                    className={`
                                        text-xs px-2 py-1 rounded-md truncate font-medium border-l-2 transition-transform hover:scale-[1.02] cursor-pointer
                                        ${getRegionClasses(event.region)}
                                    `}
                                    title={`${event.title} (${event.isAllDay ? 'All Day' : formatTime(event.start)})`}
                                >
                                    {event.isAllDay ? '' : <span className="opacity-75 mr-1 text-[10px]">{formatTime(event.start)}</span>}
                                    {event.title}
                                </div>
                            ))}
                        </div>

                        {/* Hover Plus Button (Desktop) */}
                        <div className="absolute bottom-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity hidden md:block">
                            <button 
                                onClick={(e) => {
                                    e.stopPropagation();
                                    handleDateClick(cell.date);
                                }}
                                className="bg-gray-100 p-1 rounded-full text-gray-400 hover:text-blue-600 hover:bg-blue-50 cursor-pointer"
                            >
                                <Plus size={14} />
                            </button>
                        </div>
                    </div>
                );
            })}
        </div>
      </main>

      {/* Modals */}
      <EventModal 
        isOpen={isEventModalOpen}
        onClose={() => setIsEventModalOpen(false)}
        onSave={handleSaveEvent}
        onDelete={handleDeleteEvent}
        initialDate={selectedDate}
        existingEvent={selectedEvent}
      />
    </div>
  );
};

export default App;
